<?php
namespace Tests\Feature\Hr;use Illuminate\Support\Facades\Artisan;use Illuminate\Support\Facades\Schema;use Tests\TestCase;
class HrPhase6CWorkforceRollbackTest extends TestCase{use RefreshHrDatabase;public function test_workforce_schema_exists():void{$this->assertTrue(Schema::hasColumns('hr_workforce_plans',['budget_encrypted','status','source_hash','approved_by']));$this->assertTrue(Schema::hasColumns('hr_workforce_plan_lines',['planned_fte','actual_fte_snapshot','actual_monthly_cost_encrypted']));}public function test_rollback_preserves_payroll_adjustments():void{Artisan::call('migrate:rollback',['--step'=>1]);$this->assertFalse(Schema::hasTable('hr_workforce_plans'));$this->assertTrue(Schema::hasTable('hr_payroll_adjustments'));}}
